SELECT session_id, engineer_id, firmware_id, notes
FROM debug_sessions
WHERE session_status = 'completed';

SELECT COUNT(*) AS active_engineer_count
FROM engineers
WHERE is_active = 1;

SELECT session_status
  FROM debug_sessions
  WHERE session_id = 1;

SELECT COUNT(*) AS completed_sessions
FROM debug_sessions
WHERE session_status = 'completed';

SELECT description
FROM debug_status
WHERE is_critical = 1 AND current_value = 1;

SELECT firmware_id, version
FROM firmware_versions
WHERE is_active = 1;
